        setAllItems(accumulatedRef.current);
        pageRef.current = nextPage;
      }
      setHasMore(result.hasMore && result.items.length > 0);
    } catch (err) {
      console.error(`[ProgressiveList] loadMore error for ${queryKey.join('.')}:`, err);
      setHasMore(false);
    } finally {
      setIsFetchingMore(false);
    }
